def solve(file_data):
    if not isinstance(file_data, list) or not all(isinstance(file, dict) for file in file_data):
        raise ValueError("Input must be a list of dictionaries representing files.")

    for file in file_data:
        if 'file_name' not in file or 'file_type' not in file:
            raise ValueError("Each file must contain 'file_name' and 'file_type' keys.")

        if not isinstance(file['file_name'], str) or not isinstance(file['file_type'], str):
            raise ValueError("'file_name' and 'file_type' must be strings.")

        if file['file_type'] not in ['pdf', 'doc', 'txt', 'png']:
            raise ValueError(f"Unsupported file type: {file['file_type']}")

    # Core logic to process files would go here
    return "Files processed successfully."
